'use strict';

var invalid = [];

// Simple string concatenation in Error:
var test = {
	'code': 'throw new Error( \'invalid argument. Value: `\' + value + \'`.\' );',
	'errors': [
		{
			'message': 'Use `@stdlib/string/format` instead of string concatenation in error messages.',
			'type': 'BinaryExpression'
		}
	]
};
invalid.push( test );

// String concatenation in TypeError:
test = {
	'code': 'throw new TypeError( \'expected a string. Value: `\' + x + \'`.\' );',
	'errors': [
		{
			'message': 'Use `@stdlib/string/format` instead of string concatenation in error messages.',
			'type': 'BinaryExpression'
		}
	]
};
invalid.push( test );

// String concatenation in RangeError:
test = {
	'code': 'throw new RangeError( idx + \' is out of bounds.\' );',
	'errors': [
		{
			'message': 'Use `@stdlib/string/format` instead of string concatenation in error messages.',
			'type': 'BinaryExpression'
		}
	]
};
invalid.push( test );

// Error called without new:
test = {
	'code': 'throw Error( \'invalid argument. Value: `\' + value + \'`.\' );',
	'errors': [
		{
			'message': 'Use `@stdlib/string/format` instead of string concatenation in error messages.',
			'type': 'BinaryExpression'
		}
	]
};
invalid.push( test );

// String concatenation in SyntaxError:
test = {
	'code': 'throw new SyntaxError( \'unexpected token: \' + token );',
	'errors': [
		{
			'message': 'Use `@stdlib/string/format` instead of string concatenation in error messages.',
			'type': 'BinaryExpression'
		}
	]
};
invalid.push( test );

// String concatenation in ReferenceError:
test = {
	'code': 'throw new ReferenceError( name + \' is not defined.\' );',
	'errors': [
		{
			'message': 'Use `@stdlib/string/format` instead of string concatenation in error messages.',
			'type': 'BinaryExpression'
		}
	]
};
invalid.push( test );

// String concatenation in URIError:
test = {
	'code': 'throw new URIError( \'invalid URI: \' + uri );',
	'errors': [
		{
			'message': 'Use `@stdlib/string/format` instead of string concatenation in error messages.',
			'type': 'BinaryExpression'
		}
	]
};
invalid.push( test );

// String concatenation in EvalError:
test = {
	'code': 'throw new EvalError( \'eval error: \' + msg );',
	'errors': [
		{
			'message': 'Use `@stdlib/string/format` instead of string concatenation in error messages.',
			'type': 'BinaryExpression'
		}
	]
};
invalid.push( test );


// EXPORTS //

module.exports = invalid;
